"""
#include <bits/stdc++.h>
using namespace std;

const int MAX_N = 100005;
const int MAX_M = 100005;
int N, M;
int A[MAX_N], B[MAX_N];

int main() {
  cin >> N >> M;
  for (int i = 0; i < N; i++) {
    cin >> A[i] >> B[i];
  }

  long long dp[MAX_N][MAX_M+1];
  memset(dp, 0, sizeof(dp));

  for (int i = 0; i < N; i++) {
    for (int j = 0; j <= M; j++) {
      dp[i+1][j] = max(dp[i+1][j], dp[i][j]);
      if (j + A[i] <= M) {
        dp[i+1][j+A[i]] = max(dp[i+1][j+A[i]], dp[i][j] + B[i]);
      }
    }
  }

  long long ans = 0;
  for (int i = 0; i <= M; i++) {
    ans = max(ans, dp[N][i]);
  }
  cout << ans << endl;
  return 0;
}
